import React, { useState, useEffect } from 'react';
import { useAuth } from '../../contexts/AuthContext';
import { userAPI } from '../../services/api';
import './Profile.css';

const Profile = () => {
  const [profile, setProfile] = useState({
    skills: [],
    interests: [],
    education: '',
    experience: 0,
    bio: ''
  });
  const [newSkill, setNewSkill] = useState('');
  const [newInterest, setNewInterest] = useState('');
  const [loading, setLoading] = useState(false);
  const [saving, setSaving] = useState(false);
  const [message, setMessage] = useState('');

  const { user } = useAuth();

  useEffect(() => {
    fetchProfile();
  }, []);

  const fetchProfile = async () => {
    setLoading(true);
    try {
      // Mock profile data for now
      const mockProfile = {
        skills: ['JavaScript', 'React', 'Problem Solving'],
        interests: ['Web Development', 'AI', 'UX Design'],
        education: 'Bachelor of Computer Science',
        experience: 2,
        bio: 'Passionate developer looking to grow in tech industry.'
      };
      setProfile(mockProfile);
      
      // In real app: const userData = await userAPI.getProfile();
      // setProfile(userData.profile || profile);
      
    } catch (error) {
      console.error('Error fetching profile:', error);
    } finally {
      setLoading(false);
    }
  };

  const updateProfile = async (updates) => {
    setSaving(true);
    setMessage('');
    try {
      // Mock update for now
      setProfile(updates);
      setMessage('Profile updated successfully!');
      
      // In real app: const updatedProfile = await userAPI.updateProfile(updates);
      // setProfile(updatedProfile);
      
      setTimeout(() => setMessage(''), 3000);
    } catch (error) {
      setMessage('Error updating profile');
      console.error('Error updating profile:', error);
    } finally {
      setSaving(false);
    }
  };

  const addSkill = () => {
    if (newSkill.trim() && !profile.skills.includes(newSkill.trim())) {
      const updatedSkills = [...profile.skills, newSkill.trim()];
      updateProfile({ ...profile, skills: updatedSkills });
      setNewSkill('');
    }
  };

  const removeSkill = (skillToRemove) => {
    const updatedSkills = profile.skills.filter(skill => skill !== skillToRemove);
    updateProfile({ ...profile, skills: updatedSkills });
  };

  const addInterest = () => {
    if (newInterest.trim() && !profile.interests.includes(newInterest.trim())) {
      const updatedInterests = [...profile.interests, newInterest.trim()];
      updateProfile({ ...profile, interests: updatedInterests });
      setNewInterest('');
    }
  };

  const removeInterest = (interestToRemove) => {
    const updatedInterests = profile.interests.filter(interest => interest !== interestToRemove);
    updateProfile({ ...profile, interests: updatedInterests });
  };

  const handleInputChange = (field, value) => {
    updateProfile({ ...profile, [field]: value });
  };

  if (!user) {
    return (
      <div className="profile-container">
        <div className="container">
          <div className="auth-required">
            <h2>Authentication Required</h2>
            <p>Please log in to view your profile.</p>
          </div>
        </div>
      </div>
    );
  }

  if (loading) {
    return (
      <div className="profile-container">
        <div className="container">
          <div className="loading">Loading profile...</div>
        </div>
      </div>
    );
  }

  return (
    <div className="profile-container">
      <div className="container">
        <div className="profile-header">
          <h1>Your Profile</h1>
          <p>Manage your personal information and career preferences</p>
        </div>

        {message && (
          <div className={`message ${message.includes('Error') ? 'error' : 'success'}`}>
            {message}
          </div>
        )}

        <div className="profile-content">
          {/* Personal Information */}
          <div className="profile-section">
            <h2>Personal Information</h2>
            <div className="profile-info">
              <div className="info-item">
                <label>Full Name</label>
                <p>{user.name}</p>
              </div>
              <div className="info-item">
                <label>Email</label>
                <p>{user.email}</p>
              </div>
              <div className="info-item">
                <label>Member since</label>
                <p>{new Date().toLocaleDateString()}</p>
              </div>
            </div>
          </div>

          {/* Bio */}
          <div className="profile-section">
            <h2>Bio</h2>
            <textarea
              value={profile.bio}
              onChange={(e) => handleInputChange('bio', e.target.value)}
              placeholder="Tell us about yourself, your goals, and aspirations..."
              rows="4"
            />
          </div>

          {/* Education & Experience */}
          <div className="profile-grid">
            <div className="profile-section">
              <h2>Education</h2>
              <input
                type="text"
                value={profile.education}
                onChange={(e) => handleInputChange('education', e.target.value)}
                placeholder="Your educational background"
              />
            </div>

            <div className="profile-section">
              <h2>Experience (Years)</h2>
              <input
                type="number"
                value={profile.experience}
                onChange={(e) => handleInputChange('experience', parseInt(e.target.value) || 0)}
                min="0"
                max="50"
              />
            </div>
          </div>

          {/* Skills */}
          <div className="profile-section">
            <h2>Skills</h2>
            <div className="tags-input">
              <div className="tags-list">
                {profile.skills.map((skill, index) => (
                  <span key={index} className="tag">
                    {skill}
                    <button onClick={() => removeSkill(skill)} className="remove-tag">
                      ×
                    </button>
                  </span>
                ))}
              </div>
              <div className="input-group">
                <input
                  type="text"
                  value={newSkill}
                  onChange={(e) => setNewSkill(e.target.value)}
                  onKeyPress={(e) => e.key === 'Enter' && addSkill()}
                  placeholder="Add a skill"
                />
                <button onClick={addSkill} className="btn btn-primary">
                  Add
                </button>
              </div>
            </div>
          </div>

          {/* Interests */}
          <div className="profile-section">
            <h2>Career Interests</h2>
            <div className="tags-input">
              <div className="tags-list">
                {profile.interests.map((interest, index) => (
                  <span key={index} className="tag">
                    {interest}
                    <button onClick={() => removeInterest(interest)} className="remove-tag">
                      ×
                    </button>
                  </span>
                ))}
              </div>
              <div className="input-group">
                <input
                  type="text"
                  value={newInterest}
                  onChange={(e) => setNewInterest(e.target.value)}
                  onKeyPress={(e) => e.key === 'Enter' && addInterest()}
                  placeholder="Add an interest"
                />
                <button onClick={addInterest} className="btn btn-primary">
                  Add
                </button>
              </div>
            </div>
          </div>

          {/* Save Button */}
          <div className="profile-actions">
            <button 
              onClick={() => updateProfile(profile)} 
              disabled={saving}
              className="btn btn-primary save-btn"
            >
              {saving ? 'Saving...' : 'Save Profile'}
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Profile;
